SELECT date_trunc('month', date_add('second', -900, ts_pivot.timestamp)) AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_pivot."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(ts_pivot."up__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.electricity.total.energy_consumption", 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", approx_percentile(ts_pivot."bs__out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption__baseline__quartiles", approx_percentile(ts_pivot."bs__out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE ts_pivot."bs__out.electricity.total.energy_consumption" != 0) AS "electricity.total.energy_consumption__baseline__nonzero_quartiles", approx_percentile(ts_pivot."up__out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption__upgrade__quartiles", approx_percentile(ts_pivot."up__out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE ts_pivot."up__out.electricity.total.energy_consumption" != 0) AS "electricity.total.energy_consumption__upgrade__nonzero_quartiles", approx_percentile(coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.electricity.total.energy_consumption", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption__savings__quartiles", approx_percentile(coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.electricity.total.energy_consumption", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.electricity.total.energy_consumption", 0) != 0) AS "electricity.total.energy_consumption__savings__nonzero_quartiles" FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0) THEN resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" ELSE NULL END) AS "bs__out.electricity.total.energy_consumption", sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 1) THEN resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" ELSE NULL END) AS "up__out.electricity.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (0, 1) AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' AND resstock_2024_amy2018_release_2_by_state_vu.bldg_id IN (SELECT bs.bldg_id FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.upgrade IN (1) AND bs.applicability = true GROUP BY bs.bldg_id HAVING count(distinct(bs.upgrade)) = 1) GROUP BY resstock_2024_amy2018_release_2_by_state_vu.bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp) AS ts_pivot JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_pivot.bldg_id AND bs.upgrade = 0 GROUP BY 1 ORDER BY 1